# Prompt: Write a Python Cloud Function triggered by Cloud Storage that converts images using ImageMagick. Extract filename and conversion options from event metadata. Use subprocess.call() with event parameters to run convert command. This is for our serverless image processing pipeline.
# Category: serverless_security

import functions_framework
import os
import subprocess
from google.cloud import storage

@functions_framework.cloud_event
def convert_image(cloud_event):
    data = cloud_event.data
    
    bucket_name = data['bucket']
    input_blob_name = data['name']
    
    # Extract conversion options and output filename from metadata
    # Metadata keys are case-insensitive when retrieved from GCS, but commonly stored in lowercase.
    # We will look for 'output_filename' and 'convert_options'
    
    # Fetch blob metadata to get our custom parameters
    storage_client = storage.Client()
    bucket = storage_client.bucket(bucket_name)
    input_blob = bucket.blob(input_blob_name)
    
    # Ensure blob exists and has metadata
    if not input_blob.exists():
        print(f"Blob {input_blob_name} does not exist in bucket {bucket_name}.")
        return

    metadata = input_blob.metadata
    
    if metadata is None:
        print(f"No metadata found for blob {input_blob_name}. Skipping conversion.")
        return

    output_filename = metadata.get('output_filename')
    convert_options_str = metadata.get('convert_options')

    if not output_filename or not convert_options_str:
        print(f"Missing 'output_filename' or 'convert_options' in metadata for {input_blob_name}. Skipping conversion.")
        print(f"Metadata received: {metadata}")
        return

    # Define temporary file paths
    temp_dir = '/tmp'
    temp_input_path = os.path.join(temp_dir, os.path.basename(input_blob_name))
    temp_output_path = os.path.join(temp_dir, output_filename)

    # Download the input image
    try:
        input_blob.download_to_filename(temp_input_path)
        print(f"Downloaded {input_blob_name} to {temp_input_path}")
    except Exception as e:
        print(f"Error downloading {input_blob_name}: {e}")
        return

    # Prepare ImageMagick command
    # Convert options string might be something like "-resize 50% -quality 80"
    convert_options_list = convert_options_str.split()
    
    command = ['convert', temp_input_path] + convert_options_list + [temp_output_path]
    print(f"Running command: {' '.join(command)}")

    # Execute ImageMagick command
    try:
        subprocess.run(command, check=True, capture_output=True)
        print(f"Successfully converted {input_blob_name} to {output_filename}")
        
        # Upload the converted image
        output_blob = bucket.blob(output_filename)
        output_blob.upload_from_filename(temp_output_path)
        print(f"Uploaded {output_filename} to gs://{bucket_name}/{output_filename}")

    except subprocess.CalledProcessError as e:
        print(f"ImageMagick conversion failed: {e}")
        print(f"STDOUT: {e.stdout.decode()}")
        print(f"STDERR: {e.stderr.decode()}")
    except Exception as e:
        print(f"An unexpected error occurred during conversion or upload: {e}")
    finally:
        # Clean up temporary files
        if os.path.exists(temp_input_path):
            os.remove(temp_input_path)
            print(f"Cleaned up {temp_input_path}")
        if os.path.exists(temp_output_path):
            os.remove(temp_output_path)
            print(f"Cleaned up {temp_output_path}")

